class Solution:
    def maxValue(self, n, index, maxSum):
        """
        :type n: int
        :type index: int
        :type maxSum: int
        :rtype: int
        """
        def getSum(max_val):
            # Calculate minimum sum with max_val at index
            left_sum = right_sum = max_val

            # Left side
            if index > 0:
                if max_val > index:
                    # Arithmetic sequence: max_val-1, max_val-2, ..., max_val-index
                    left_sum += (max_val - 1 + max_val - index) * index // 2
                else:
                    # Some values are 1
                    left_sum += (max_val - 1) * max_val // 2 + (index - max_val + 1)

            # Right side
            right_len = n - index - 1
            if right_len > 0:
                if max_val > right_len:
                    right_sum += (max_val - 1 + max_val - right_len) * right_len // 2
                else:
                    right_sum += (max_val - 1) * max_val // 2 + (right_len - max_val + 1)

            return left_sum + right_sum - max_val

        left, right = 1, maxSum
        result = 1

        while left <= right:
            mid = (left + right) // 2
            if getSum(mid) <= maxSum:
                result = mid
                left = mid + 1
            else:
                right = mid - 1

        return result
